};

// Game.h
class Game {
public:
    void PropagateInputEvent(const InputEvent& inputEvent); // Propagates input events to registered components
};
```

This implementation allows for clean separation of input handling responsibilities and enables the game class, which runs the main loop, to propagate input events efficiently from the window class to all interested components.

Explain how the following C++ code calculates barycentric coordinates for a triangle. Don't explain the code, but the theory behind it.

Vec3f barycentric(const std::array<Vec3f, 3> pts, const Vec3f& p) {
    const auto [a, b, c] = pts;

    const auto ab = b - a;
    const auto ac = c - a;
    const auto ap = p - a;

    const float den = ab.x * ac.y - ac.x * ab.y;
    const float v = (ap.x * ac.y - ac.x * ap.y) / den;
    const float w = (ab.x * ap.y - ap.x * ab.y) / den;
    const float u = 1.0f - v - w;

    return {u, v, w};
}

def buildCountTrueBits(bus: Bus): Bus =
  require(bus.length > 0, "Can not build a true bit counter on an empty bus")
  val totalCountBits = log2ceil(bus.length)
  val countBuses = Array.fill(bus.length)(new Bus(totalCountBits))

  for (bitIndex <- 0 until bus.length) {
    val bitValue = bus(bitIndex)
    for (countBitIndex <- 0 until totalCountBits) {
      countBuses(bitIndex)(countBitIndex) = if countBitIndex == 0 then bitValue else Gate.False
    }
  }

  countBuses.reduce(buildAdderNoOverflow)
end buildCountTrueBits

